import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void crossShape() {
        int[][] grid = {
            {0, 1, 0, 0},
            {1, 1, 1, 0},
            {0, 1, 0, 0}
        };
        assertEquals(12, new Solution().islandPerimeter(grid));
    }

    @Test
    void singleCell() {
        int[][] grid = {{1}};
        assertEquals(4, new Solution().islandPerimeter(grid));
    }

    @Test
    void horizontalStrip() {
        int[][] grid = {{1, 1}};
        assertEquals(6, new Solution().islandPerimeter(grid));
    }

    @Test
    void emptyGrid() {
        int[][] grid = {};
        assertEquals(0, new Solution().islandPerimeter(grid));
    }

    @Test
    void noLand() {
        int[][] grid = {{1, 0}, {0, 0}};
        // This grid has 1 land cell at (0,0); edges: up=boundary, left=boundary, right=0, down=0 → 4
        assertEquals(4, new Solution().islandPerimeter(grid));
    }

    @Test
    void solidTwoByTwo() {
        // 4 cells, each contributes edges to boundary; 4 internal shared edges
        // Total = 4*4 - 2*4 = 8
        int[][] grid = {
            {1, 1},
            {1, 1}
        };
        assertEquals(8, new Solution().islandPerimeter(grid));
    }

    @Test
    void verticalStrip() {
        int[][] grid = {
            {1},
            {1},
            {1}
        };
        // 3 cells in a column: 3*4 - 2*2 = 8
        assertEquals(8, new Solution().islandPerimeter(grid));
    }
}
